    // ✅ SETTINGS APPLY (globál)
    this.sub = this.ui.state$.subscribe((s: any) => {
      document.body.classList.toggle('dark', !!s.darkMode);
      document.body.classList.toggle('compact', !!s.compactLayout);

      // ha később akarsz accentet is:
