import { Product } from '../../../../Models/Product/product.model';

const str = (v: any) => String(v ?? '').trim();

const toInt = (v: any): number | null => {
  if (v == null || v === '') return null;

  if (typeof v === 'number') {
    return Number.isFinite(v) ? Math.round(v) : null;
  }

  const s = String(v).trim().replace(/\s+/g, '').replace(/,/g, '.');
  const nums = (s.match(/-?\d+(\.\d+)?/g) || []).map(Number).filter(Number.isFinite);

  if (!nums.length) return null;
  if (nums.length === 1) return Math.round(nums[0]);

  const min = Math.min(...nums);
  const max = Math.max(...nums);
  return Math.round((min + max) / 2);
};

function findLoosePrice(obj: any): any {
  if (!obj || typeof obj !== 'object') return null;

  const preferredKeys = [
    'price',
    'Price',
    'price_range',
    'Price Range (Ft)',
    'price_ft',
    'price_huf',
    'Price (Ft)',
    'Price Ft',
    'Unit Price',
    'Current Price',
    'Retail Price',
    'Sale Price'
  ];

  for (const key of preferredKeys) {
    if (obj[key] != null && obj[key] !== '') {
      return obj[key];
    }
  }

  for (const key of Object.keys(obj)) {
    const k = key.toLowerCase();
    if (
      k.includes('price') ||
      k.includes('ár') ||
      k.includes('ar') ||
      k.includes('ft') ||
      k.includes('huf')
    ) {
      const value = obj[key];
      if (value != null && value !== '') return value;
    }
  }

  return null;
}

export function normalizeProduct(raw: any): Product {
  const d = raw?.data ?? raw ?? {};

  const id =
    toInt(raw?.id) ??
    toInt(raw?.ID) ??
    toInt(d?.id) ??
    toInt(d?.ID) ??
    0;

  const manufacturer =
    str(raw?.manufacturer) ||
    str(raw?.Manufacturer) ||
    str(d?.manufacturer) ||
    str(d?.Manufacturer) ||
    str(d?.brand) ||
    str(d?.Brand);

  const model =
    str(raw?.model) ||
    str(raw?.Model) ||
    str(d?.model) ||
    str(d?.Model) ||
    str(d?.name) ||
    str(d?.Name);

  const table_name =
    str(raw?.table_name) ||
    str(raw?.table) ||
    str(d?.table_name) ||
    str(d?.table);

  const category = str(raw?.category) || str(d?.category);
  const type = str(raw?.type) || str(d?.type);

  const priceRaw =
    raw?.price ??
    raw?.Price ??
    raw?.price_range ??
    raw?.['Price Range (Ft)'] ??
    d?.price ??
    d?.Price ??
    d?.price_range ??
    d?.['Price Range (Ft)'] ??
    findLoosePrice(raw) ??
    findLoosePrice(d);

  const priceNum = toInt(priceRaw);
  const price = (priceNum != null && priceNum > 0) ? priceNum : null;

  return {
    id,
    manufacturer,
    model,
    price,
    table: table_name,
    table_name: table_name,
    category: category || undefined,
    type: type || undefined,
    data: d
  };
}

export function normalizeList(list: any[]): Product[] {
  return (list || []).map(x => normalizeProduct(x));
}

import { Injectable } from '@angular/core';

type ImageMap = Record<string, Record<string, string[]>>;

@Injectable({ providedIn: 'root' })
export class ImageService {
  private map: ImageMap | null = null;

  async load() {
    if (this.map) return;

    const res = await fetch('/api/images/map');
    if (!res.ok) {
      console.warn('❌ /api/images/map not reachable');
      this.map = {};
      return;
    }

    const json = await res.json();
    this.map = json as ImageMap;

    console.log('🖼 IMAGE MAP LOADED:', this.map);
  }

  getImages(table: string, product: any): string[] {
    if (!this.map || !table || !product) return [];

    const tableKey = this.normalizeTable(table);
    const id = String(
      product.id ??
      product.ID ??
      product?.data?.id ??
      product?.data?.ID ??
      ''
    ).trim();

    if (!id) return [];

    return this.map?.[tableKey]?.[id] ?? [];
  }

  getImage(table: string, product: any): string {
    const images = this.getImages(table, product);
    return images[0] || this.fallback();
  }

  private fallback() {
    return 'https://via.placeholder.com/200?text=No+Image';
  }

  private normalizeTable(table: string): string {
    return String(table || '')
      .toLowerCase()
      .replace('public.', '')
      .replace(/[_\s]+/g, '_')
      .trim();
  }
}

import { Injectable } from '@angular/core';
import { BehaviorSubject } from 'rxjs';

export type UiSettings = {
  darkMode: boolean;
  setupMode: boolean;
  compactLayout: boolean;
  autoOpenProduct: boolean;
  language: string;
  accent: string;
  publicProfile: boolean;
  rememberFilters: boolean;
};

const DEFAULT_SETTINGS: UiSettings = {
  darkMode: true,
  setupMode: false,
  compactLayout: false,
  autoOpenProduct: true,
  language: 'hu',
  accent: 'purple',
  publicProfile: true,
  rememberFilters: true,
};

@Injectable({ providedIn: 'root' })
export class UiSettingsService {
  private readonly KEY = 'ui-settings';

  private _state = new BehaviorSubject<UiSettings>(this.load());
  readonly state$ = this._state.asObservable();

  get value(): UiSettings {
    return this._state.value;
  }

  update(patch: Partial<UiSettings>) {
    const next = { ...this.value, ...patch };
    this._state.next(next);
    localStorage.setItem(this.KEY, JSON.stringify(next));
  }

  private load(): UiSettings {
    try {
      const raw = localStorage.getItem(this.KEY);
      return raw ? { ...DEFAULT_SETTINGS, ...JSON.parse(raw) } : DEFAULT_SETTINGS;
    } catch {
      return DEFAULT_SETTINGS;
    }
  }
}

