function hexToRgb(hex: string) {
  const m = hex.match(/^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i);
  if (!m) return { r: 0, g: 0, b: 0 };
  return {
    r: parseInt(m[1], 16),
    g: parseInt(m[2], 16),
    b: parseInt(m[3], 16)
  };
}

const throttle = (fn: (...args: any[]) => void, limitMs: number) => {
  let last = 0;
  return (...args: any[]) => {
    const now = performance.now();
    if (now - last >= limitMs) {
      last = now;
      fn(...args);
    }
  };
};

