/* BAL OLDAL: EZ A DRAG BOUNDARY */
.setup-workspace {
  position: relative;
  width: 100%;
  height: 100%;
  overflow: auto;
  min-height: 0;

  border-radius: 16px;
  border: 1px solid rgba(255, 255, 255, 0.10);

  /* ❌ FONTOS: backdrop-filter innen KIKERÜL, mert bugolja a position:fixed + CDK drag-ot */
  /* backdrop-filter: blur(10px); */

  /* a háttér/blend marad, de blur a ::before-ben lesz */
  background: transparent;

  box-shadow: 0 18px 60px rgba(0, 0, 0, 0.55);
}

/* ✅ Blur + háttér pseudo-elemen: így a fixed panelek nem ugranak */
.setup-workspace::before {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: 16px;

  background: rgba(10, 10, 10, 0.35);
  backdrop-filter: blur(10px);

  z-index: 0;
  pointer-events: none;
}

/* ✅ felső gombsor: Új setup + Vissza */
.toolbar {
  position: absolute;
  top: 12px;
